//! Mock value-space strategies and live-first connection classification.
//!
//! Defines how mock return values are sourced during exploration.
//! The live-first strategy attempts a real call first, recording its result
//! for the behavior map on success or falling back to autonomous mocking
//! when the dependency is unavailable (connection refused, DNS failure, etc.).

use serde::{Deserialize, Serialize};

use crate::auto_mock::IoCategory;
use crate::execution_record::ErrorInfo;

// ---------------------------------------------------------------------------
// Connection failure heuristic patterns
// ---------------------------------------------------------------------------

/// Substrings in error messages that indicate a connection was refused.
pub const CONNECTION_REFUSED_PATTERNS: &[&str] = &[
    "ECONNREFUSED",
    "connection refused",
    "Connection refused",
];

/// Substrings in error messages that indicate a DNS resolution failure.
pub const DNS_FAILURE_PATTERNS: &[&str] = &[
    "ENOTFOUND",
    "EAI_AGAIN",
    "getaddrinfo",
    "dns resolution failed",
    "no such host",
    "Name or service not known",
];

/// Substrings in error messages that indicate an authentication/authorization failure.
pub const AUTH_FAILURE_PATTERNS: &[&str] = &[
    "EAUTH",
    "authentication failed",
    "Authentication failed",
    "unauthorized",
    "Unauthorized",
    "403 Forbidden",
    "401 Unauthorized",
    "invalid credentials",
    "access denied",
    "Access denied",
];

/// Substrings in error messages that indicate a network timeout.
pub const TIMEOUT_PATTERNS: &[&str] = &[
    "ETIMEDOUT",
    "ESOCKETTIMEDOUT",
    "ENETUNREACH",
    "connect ETIMEDOUT",
    "request timed out",
    "Request timed out",
    "socket hang up",
    "network timeout",
];

/// Error type names that indicate infrastructure-level failures.
pub const INFRA_ERROR_TYPES: &[&str] = &[
    "ConnectionError",
    "NetworkError",
    "TimeoutError",
    "SocketError",
    "DNSError",
    "FetchError",
];

// ---------------------------------------------------------------------------
// MockValueSpace enum
// ---------------------------------------------------------------------------

/// Strategy for sourcing mock return values during exploration.
///
/// Ordered from most realistic (real calls) to most synthetic (seeded fixtures).
/// The orchestrator selects a strategy per-dependency based on availability
/// and user configuration.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MockValueSpace {
    /// Try the real dependency first. On success, record the result for the
    /// behavior map. On connection failure, switch to [`Autonomous`](Self::Autonomous).
    LiveFirst,
    /// Use a fixed set of return values (from config or behavior map).
    /// No live calls are attempted.
    FixedSet,
    /// Generate return values autonomously from type information and
    /// dependency classification. Used when the real dependency is unavailable.
    Autonomous,
    /// Use a user-provided seed corpus of return values, mutating them
    /// for diversity while preserving structural validity.
    Seeded,
}

impl MockValueSpace {
    /// The default strategy for I/O categories that involve network or
    /// database access: try live first, fall back to autonomous on failure.
    pub fn default_for_category(category: IoCategory) -> Self {
        match category {
            IoCategory::Network | IoCategory::Database => Self::LiveFirst,
            IoCategory::FileSystem => Self::Autonomous,
            IoCategory::PureUtility => Self::FixedSet,
            IoCategory::ExternalOther => Self::Autonomous,
        }
    }
}

impl std::fmt::Display for MockValueSpace {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::LiveFirst => write!(f, "live_first"),
            Self::FixedSet => write!(f, "fixed_set"),
            Self::Autonomous => write!(f, "autonomous"),
            Self::Seeded => write!(f, "seeded"),
        }
    }
}

// ---------------------------------------------------------------------------
// Connection failure classification
// ---------------------------------------------------------------------------

/// Result of classifying an execution error for live-first logic.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LiveCallOutcome {
    /// The call succeeded (no error). Record the result.
    Success,
    /// The dependency is unavailable (connection refused, DNS, auth, timeout).
    /// Switch to autonomous mocking.
    ConnectionFailure,
    /// The call reached the dependency but it returned an application-level
    /// error (e.g. 404, validation error). This is a real behavior to record.
    ApplicationError,
}

/// Classify an execution error as a connection failure or application error.
///
/// Connection failures indicate the dependency is unavailable and the
/// orchestrator should fall back to autonomous mocking. Application errors
/// are real behaviors that should be recorded in the behavior map.
///
/// Returns [`LiveCallOutcome::ConnectionFailure`] when the error message or
/// type matches known infrastructure failure patterns.
pub fn classify_live_call_error(error: &ErrorInfo) -> LiveCallOutcome {
    // Check error type first — more specific signal
    if INFRA_ERROR_TYPES
        .iter()
        .any(|t| error.error_type.contains(t))
    {
        return LiveCallOutcome::ConnectionFailure;
    }

    let msg = &error.message;

    if CONNECTION_REFUSED_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }
    if DNS_FAILURE_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }
    if AUTH_FAILURE_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }
    if TIMEOUT_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }

    // Check the structured error_category field from the frontend
    if let Some(ref cat) = error.error_category {
        if cat == "infrastructure" {
            return LiveCallOutcome::ConnectionFailure;
        }
    }

    LiveCallOutcome::ApplicationError
}

/// Classify the result of a live call attempt.
///
/// `None` error means success; `Some` error is classified via heuristics.
pub fn classify_live_call_result(error: Option<&ErrorInfo>) -> LiveCallOutcome {
    match error {
        None => LiveCallOutcome::Success,
        Some(err) => classify_live_call_error(err),
    }
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;

    fn make_error(error_type: &str, message: &str) -> ErrorInfo {
        ErrorInfo {
            error_type: error_type.to_string(),
            message: message.to_string(),
            stack: None,
            error_category: None,
        }
    }

    fn make_error_with_category(
        error_type: &str,
        message: &str,
        category: &str,
    ) -> ErrorInfo {
        ErrorInfo {
            error_type: error_type.to_string(),
            message: message.to_string(),
            stack: None,
            error_category: Some(category.to_string()),
        }
    }

    // -- MockValueSpace basics --

    #[test]
    fn mock_value_space_display() {
        assert_eq!(MockValueSpace::LiveFirst.to_string(), "live_first");
        assert_eq!(MockValueSpace::FixedSet.to_string(), "fixed_set");
        assert_eq!(MockValueSpace::Autonomous.to_string(), "autonomous");
        assert_eq!(MockValueSpace::Seeded.to_string(), "seeded");
    }

    #[test]
    fn default_strategy_for_network_is_live_first() {
        assert_eq!(
            MockValueSpace::default_for_category(IoCategory::Network),
            MockValueSpace::LiveFirst
        );
    }

    #[test]
    fn default_strategy_for_database_is_live_first() {
        assert_eq!(
            MockValueSpace::default_for_category(IoCategory::Database),
            MockValueSpace::LiveFirst
        );
    }

    #[test]
    fn default_strategy_for_filesystem_is_autonomous() {
        assert_eq!(
            MockValueSpace::default_for_category(IoCategory::FileSystem),
            MockValueSpace::Autonomous
        );
    }

    #[test]
    fn default_strategy_for_pure_utility_is_fixed_set() {
        assert_eq!(
            MockValueSpace::default_for_category(IoCategory::PureUtility),
            MockValueSpace::FixedSet
        );
    }

    #[test]
    fn default_strategy_for_external_other_is_autonomous() {
        assert_eq!(
            MockValueSpace::default_for_category(IoCategory::ExternalOther),
            MockValueSpace::Autonomous
        );
    }

    // -- classify_live_call_result --

    #[test]
    fn no_error_is_success() {
        assert_eq!(classify_live_call_result(None), LiveCallOutcome::Success);
    }

    // -- Connection refused --

    #[test]
    fn econnrefused_is_connection_failure() {
        let err = make_error("Error", "connect ECONNREFUSED 127.0.0.1:5432");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    #[test]
    fn connection_refused_lowercase() {
        let err = make_error("Error", "connection refused");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    // -- DNS failure --

    #[test]
    fn enotfound_is_connection_failure() {
        let err = make_error("Error", "getaddrinfo ENOTFOUND api.example.com");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    #[test]
    fn no_such_host_is_connection_failure() {
        let err = make_error("Error", "dial tcp: lookup db.internal: no such host");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    // -- Auth failure --

    #[test]
    fn auth_401_is_connection_failure() {
        let err = make_error("Error", "Request failed with status 401 Unauthorized");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    #[test]
    fn auth_403_is_connection_failure() {
        let err = make_error("Error", "403 Forbidden");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    #[test]
    fn access_denied_is_connection_failure() {
        let err = make_error("Error", "Access denied for user 'root'@'localhost'");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    // -- Timeout --

    #[test]
    fn etimedout_is_connection_failure() {
        let err = make_error("Error", "connect ETIMEDOUT 10.0.0.1:443");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    #[test]
    fn socket_hang_up_is_connection_failure() {
        let err = make_error("Error", "socket hang up");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    // -- Error type classification --

    #[test]
    fn connection_error_type_is_connection_failure() {
        let err = make_error("ConnectionError", "could not connect");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    #[test]
    fn timeout_error_type_is_connection_failure() {
        let err = make_error("TimeoutError", "operation timed out");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    #[test]
    fn fetch_error_type_is_connection_failure() {
        let err = make_error("FetchError", "request to https://api.example.com failed");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    // -- Structured category --

    #[test]
    fn infrastructure_category_is_connection_failure() {
        let err = make_error_with_category("Error", "something broke", "infrastructure");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ConnectionFailure);
    }

    // -- Application errors --

    #[test]
    fn http_404_is_application_error() {
        let err = make_error("Error", "Request failed with status code 404");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ApplicationError);
    }

    #[test]
    fn validation_error_is_application_error() {
        let err = make_error("ValidationError", "email field is required");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ApplicationError);
    }

    #[test]
    fn generic_error_is_application_error() {
        let err = make_error("Error", "something went wrong");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ApplicationError);
    }

    #[test]
    fn runtime_category_is_application_error() {
        let err = make_error_with_category("Error", "null pointer", "runtime");
        assert_eq!(classify_live_call_error(&err), LiveCallOutcome::ApplicationError);
    }

    // -- Serialization roundtrip --

    #[test]
    fn mock_value_space_serde_roundtrip() {
        let variants = [
            MockValueSpace::LiveFirst,
            MockValueSpace::FixedSet,
            MockValueSpace::Autonomous,
            MockValueSpace::Seeded,
        ];
        for variant in &variants {
            let json = serde_json::to_string(variant).expect("serialize");
            let back: MockValueSpace = serde_json::from_str(&json).expect("deserialize");
            assert_eq!(*variant, back);
        }
    }

    // -- Proptest --

    mod proptests {
        use super::*;
        use proptest::prelude::*;

        /// Arbitrary MockValueSpace variant.
        fn arb_mock_value_space() -> impl Strategy<Value = MockValueSpace> {
            prop_oneof![
                Just(MockValueSpace::LiveFirst),
                Just(MockValueSpace::FixedSet),
                Just(MockValueSpace::Autonomous),
                Just(MockValueSpace::Seeded),
            ]
        }

        /// Arbitrary IoCategory variant.
        fn arb_io_category() -> impl Strategy<Value = IoCategory> {
            prop_oneof![
                Just(IoCategory::FileSystem),
                Just(IoCategory::Network),
                Just(IoCategory::Database),
                Just(IoCategory::PureUtility),
                Just(IoCategory::ExternalOther),
            ]
        }

        proptest! {
            /// Serde roundtrip holds for all variants.
            #[test]
            fn serde_roundtrip(space in arb_mock_value_space()) {
                let json = serde_json::to_string(&space).unwrap();
                let back: MockValueSpace = serde_json::from_str(&json).unwrap();
                prop_assert_eq!(space, back);
            }

            /// Display output matches serde serialization (without quotes).
            #[test]
