/// Strategy for sourcing mock return values during exploration.
///
/// Ordered from most realistic (real calls) to most synthetic (seeded fixtures).
/// The orchestrator selects a strategy per-dependency based on availability
/// and user configuration.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MockValueSpace {
    /// Try the real dependency first. On success, record the result for the
    /// behavior map. On connection failure, switch to [`Autonomous`](Self::Autonomous).
    LiveFirst,
    /// Use a fixed set of return values (from config or behavior map).
    /// No live calls are attempted.
    FixedSet,
    /// Generate return values autonomously from type information and
    /// dependency classification. Used when the real dependency is unavailable.
    Autonomous,
    /// Use a user-provided seed corpus of return values, mutating them
    /// for diversity while preserving structural validity.
    Seeded,
}

impl MockValueSpace {
    /// The default strategy for I/O categories that involve network or
    /// database access: try live first, fall back to autonomous on failure.
    pub fn default_for_category(category: IoCategory) -> Self {
        match category {
            IoCategory::Network | IoCategory::Database => Self::LiveFirst,
            IoCategory::FileSystem => Self::Autonomous,
            IoCategory::PureUtility => Self::FixedSet,
            IoCategory::ExternalOther => Self::Autonomous,
        }
    }
}

impl std::fmt::Display for MockValueSpace {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::LiveFirst => write!(f, "live_first"),
            Self::FixedSet => write!(f, "fixed_set"),
            Self::Autonomous => write!(f, "autonomous"),
            Self::Seeded => write!(f, "seeded"),
        }
    }
}

// ---------------------------------------------------------------------------
// Connection failure classification
// ---------------------------------------------------------------------------

/// Result of classifying an execution error for live-first logic.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LiveCallOutcome {
    /// The call succeeded (no error). Record the result.
    Success,
    /// The dependency is unavailable (connection refused, DNS, auth, timeout).
    /// Switch to autonomous mocking.
    ConnectionFailure,
    /// The call reached the dependency but it returned an application-level
    /// error (e.g. 404, validation error). This is a real behavior to record.
    ApplicationError,
}

/// Classify an execution error as a connection failure or application error.
///
/// Connection failures indicate the dependency is unavailable and the
/// orchestrator should fall back to autonomous mocking. Application errors
/// are real behaviors that should be recorded in the behavior map.
///
/// Returns [`LiveCallOutcome::ConnectionFailure`] when the error message or
/// type matches known infrastructure failure patterns.
pub fn classify_live_call_error(error: &ErrorInfo) -> LiveCallOutcome {
    // Check error type first — more specific signal
    if INFRA_ERROR_TYPES
        .iter()
        .any(|t| error.error_type.contains(t))
    {
        return LiveCallOutcome::ConnectionFailure;
    }

    let msg = &error.message;

    if CONNECTION_REFUSED_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }
    if DNS_FAILURE_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }
    if AUTH_FAILURE_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }
    if TIMEOUT_PATTERNS.iter().any(|p| msg.contains(p)) {
        return LiveCallOutcome::ConnectionFailure;
    }

    // Check the structured error_category field from the frontend
    if let Some(ref cat) = error.error_category {
        if cat == "infrastructure" {
            return LiveCallOutcome::ConnectionFailure;
        }
    }

    LiveCallOutcome::ApplicationError
}

/// Classify the result of a live call attempt.
///
/// `None` error means success; `Some` error is classified via heuristics.
pub fn classify_live_call_result(error: Option<&ErrorInfo>) -> LiveCallOutcome {
    match error {
        None => LiveCallOutcome::Success,
        Some(err) => classify_live_call_error(err),
    }
}

