    // -- Serialization roundtrip --

    #[test]
    fn mock_value_space_serde_roundtrip() {
        let variants = [
            MockValueSpace::LiveFirst,
            MockValueSpace::FixedSet,
            MockValueSpace::Autonomous,
            MockValueSpace::Seeded,
        ];
        for variant in &variants {
            let json = serde_json::to_string(variant).expect("serialize");
            let back: MockValueSpace = serde_json::from_str(&json).expect("deserialize");
            assert_eq!(*variant, back);
        }
    }

    // -- Proptest --

    mod proptests {
        use super::*;
        use proptest::prelude::*;

        fn arb_mock_value_space() -> impl Strategy<Value = MockValueSpace> {
            prop_oneof![
                Just(MockValueSpace::LiveFirst),
                Just(MockValueSpace::FixedSet),
                Just(MockValueSpace::Autonomous),
                Just(MockValueSpace::Seeded),
            ]
        }

        fn arb_io_category() -> impl Strategy<Value = IoCategory> {
            prop_oneof![
                Just(IoCategory::FileSystem),
                Just(IoCategory::Network),
                Just(IoCategory::Database),
                Just(IoCategory::PureUtility),
                Just(IoCategory::ExternalOther),
            ]
        }

        proptest! {
            /// Serde roundtrip holds for all variants.
            #[test]
            fn serde_roundtrip(space in arb_mock_value_space()) {
                let json = serde_json::to_string(&space).unwrap();
                let back: MockValueSpace = serde_json::from_str(&json).unwrap();
                prop_assert_eq!(space, back);
            }

            /// Display output matches serde serialization (without quotes).
            #[test]
            fn display_matches_serde(space in arb_mock_value_space()) {
                let display = space.to_string();
                let serde = serde_json::to_string(&space).unwrap();
                let serde_inner = serde.trim_matches('"');
                prop_assert_eq!(display, serde_inner);
            }

            /// default_for_category always returns a valid variant
            /// and network/database always get LiveFirst.
            #[test]
            fn default_for_category_is_total(cat in arb_io_category()) {
                let result = MockValueSpace::default_for_category(cat);
                if cat == IoCategory::Network || cat == IoCategory::Database {
                    prop_assert_eq!(result, MockValueSpace::LiveFirst);
                }
                let _ = result.to_string();
            }

            /// Connection failure patterns never classify as Success.
            #[test]
            fn connection_pattern_never_success(
                pattern_idx in 0..CONNECTION_REFUSED_PATTERNS.len(),
                prefix in "[a-z ]{0,20}",
                suffix in "[a-z ]{0,20}",
            ) {
                let pattern = CONNECTION_REFUSED_PATTERNS[pattern_idx];
                let msg = format!("{prefix}{pattern}{suffix}");
                let err = ErrorInfo {
                    error_type: "Error".to_string(),
                    message: msg,
                    stack: None,
                    error_category: None,
                };
                let outcome = classify_live_call_error(&err);
                prop_assert_eq!(outcome, LiveCallOutcome::ConnectionFailure);
            }

            /// DNS failure patterns are classified as connection failures.
            #[test]
            fn dns_pattern_is_connection_failure(
                pattern_idx in 0..DNS_FAILURE_PATTERNS.len(),
                prefix in "[a-z ]{0,20}",
                suffix in "[a-z ]{0,20}",
            ) {
                let pattern = DNS_FAILURE_PATTERNS[pattern_idx];
                let msg = format!("{prefix}{pattern}{suffix}");
                let err = ErrorInfo {
                    error_type: "Error".to_string(),
                    message: msg,
                    stack: None,
                    error_category: None,
                };
                let outcome = classify_live_call_error(&err);
                prop_assert_eq!(outcome, LiveCallOutcome::ConnectionFailure);
            }

            /// Timeout patterns are classified as connection failures.
            #[test]
            fn timeout_pattern_is_connection_failure(
                pattern_idx in 0..TIMEOUT_PATTERNS.len(),
                prefix in "[a-z ]{0,20}",
                suffix in "[a-z ]{0,20}",
            ) {
                let pattern = TIMEOUT_PATTERNS[pattern_idx];
                let msg = format!("{prefix}{pattern}{suffix}");
                let err = ErrorInfo {
                    error_type: "Error".to_string(),
                    message: msg,
                    stack: None,
                    error_category: None,
                };
                let outcome = classify_live_call_error(&err);
                prop_assert_eq!(outcome, LiveCallOutcome::ConnectionFailure);
            }

            /// Infra error types are classified as connection failures
            /// regardless of message content.
            #[test]
            fn infra_error_type_is_connection_failure(
                type_idx in 0..INFRA_ERROR_TYPES.len(),
                message in ".*",
            ) {
                let err = ErrorInfo {
                    error_type: INFRA_ERROR_TYPES[type_idx].to_string(),
                    message,
                    stack: None,
                    error_category: None,
                };
                let outcome = classify_live_call_error(&err);
                prop_assert_eq!(outcome, LiveCallOutcome::ConnectionFailure);
            }

            /// An error with no matching pattern and no infra category
            /// is classified as ApplicationError.
            #[test]
            fn generic_message_is_application_error(
                message in "[a-z]{1,50}",
            ) {
                let all_patterns: Vec<&str> = CONNECTION_REFUSED_PATTERNS
                    .iter()
                    .chain(DNS_FAILURE_PATTERNS.iter())
                    .chain(AUTH_FAILURE_PATTERNS.iter())
                    .chain(TIMEOUT_PATTERNS.iter())
                    .copied()
                    .collect();
                prop_assume!(!all_patterns.iter().any(|p| message.contains(p)));

                let err = ErrorInfo {
                    error_type: "Error".to_string(),
                    message,
                    stack: None,
                    error_category: None,
                };
                let outcome = classify_live_call_error(&err);
                prop_assert_eq!(outcome, LiveCallOutcome::ApplicationError);
            }

            /// classify_live_call_result(None) is always Success.
            #[test]
            fn none_error_is_always_success(_dummy in 0..1u32) {
                prop_assert_eq!(classify_live_call_result(None), LiveCallOutcome::Success);
            }
        }
    }
}
